  ('fire-eq-tech-moex-02930', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「六類公共危險物品緊急應變搶救代碼標示內容及位置注意要點」的規定，有關六類公共危險物品 於容器外部標示緊急應變搶救代碼之事宜，下列敘述何者正確？', '["搶救代碼第1個英文字母Y是代表應穿著全身包覆之化學防護衣", "搶救代碼數字1代表優先使用水霧滅火劑", "搶救代碼第2個英文字母E是代表應將事故發生附近人員疏散", "所標示之數字及英文字母，每字最小尺寸為長3公分，寬3公分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
